import{_ as e,o as a,c as o,a4 as n}from"./chunks/framework.DiadTcoQ.js";const c=JSON.parse('{"title":"La négation et les questions","description":"","frontmatter":{},"headers":[],"relativePath":"module-2/negation-questions.md","filePath":"module-2/negation-questions.md"}'),s={name:"module-2/negation-questions.md"};function r(d,t,i,l,u,m){return a(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="la-negation-et-les-questions" tabindex="-1">La négation et les questions <a class="header-anchor" href="#la-negation-et-les-questions" aria-label="Permalink to “La négation et les questions”">​</a></h1><h2 id="la-negation" tabindex="-1">La négation <a class="header-anchor" href="#la-negation" aria-label="Permalink to “La négation”">​</a></h2><p>En espagnol, on place <strong>no</strong> directement devant le verbe. C&#39;est tout.</p><blockquote><p><em>Hablo español.</em> — Je parle espagnol. <em>No hablo español.</em> — Je ne parle pas espagnol.</p></blockquote><p>Pas de &quot;ne...pas&quot; à construire, pas de auxiliaire : juste <strong>no</strong>.</p><h3 id="double-negation" tabindex="-1">Double négation <a class="header-anchor" href="#double-negation" aria-label="Permalink to “Double négation”">​</a></h3><p>Contrairement au français, la double négation est correcte en espagnol :</p><table tabindex="0"><thead><tr><th>Espagnol</th><th>Français</th></tr></thead><tbody><tr><td><em>No tengo nada.</em></td><td>Je n&#39;ai rien.</td></tr><tr><td><em>No hay nadie.</em></td><td>Il n&#39;y a personne.</td></tr><tr><td><em>No voy nunca.</em></td><td>Je n&#39;y vais jamais.</td></tr></tbody></table><p>Les mots négatifs courants :</p><table tabindex="0"><thead><tr><th>Positif</th><th>Négatif</th><th>Sens</th></tr></thead><tbody><tr><td>algo</td><td>nada</td><td>quelque chose / rien</td></tr><tr><td>alguien</td><td>nadie</td><td>quelqu&#39;un / personne</td></tr><tr><td>siempre</td><td>nunca / jamás</td><td>toujours / jamais</td></tr><tr><td>también</td><td>tampoco</td><td>aussi / non plus</td></tr></tbody></table><h2 id="les-questions" tabindex="-1">Les questions <a class="header-anchor" href="#les-questions" aria-label="Permalink to “Les questions”">​</a></h2><h3 id="l-intonation" tabindex="-1">L&#39;intonation <a class="header-anchor" href="#l-intonation" aria-label="Permalink to “L&#39;intonation”">​</a></h3><p>La façon la plus simple de poser une question : garder l&#39;ordre des mots et monter l&#39;intonation.</p><blockquote><p><em>¿Hablas español?</em> — Tu parles espagnol ?</p></blockquote><p>En espagnol écrit, le point d&#39;interrogation ouvrant <strong>¿</strong> est obligatoire.</p><h3 id="inverser-sujet-et-verbe" tabindex="-1">Inverser sujet et verbe <a class="header-anchor" href="#inverser-sujet-et-verbe" aria-label="Permalink to “Inverser sujet et verbe”">​</a></h3><p>On peut aussi inverser :</p><blockquote><p><em>¿Habla usted inglés?</em> — Parlez-vous anglais ?</p></blockquote><h3 id="les-mots-interrogatifs" tabindex="-1">Les mots interrogatifs <a class="header-anchor" href="#les-mots-interrogatifs" aria-label="Permalink to “Les mots interrogatifs”">​</a></h3><table tabindex="0"><thead><tr><th>Espagnol</th><th>Français</th></tr></thead><tbody><tr><td>¿qué?</td><td>quoi / que / quel ?</td></tr><tr><td>¿quién? / ¿quiénes?</td><td>qui ?</td></tr><tr><td>¿dónde?</td><td>où ?</td></tr><tr><td>¿cuándo?</td><td>quand ?</td></tr><tr><td>¿cómo?</td><td>comment ?</td></tr><tr><td>¿cuánto / cuánta?</td><td>combien ?</td></tr><tr><td>¿cuántos / cuántas?</td><td>combien (pluriel) ?</td></tr><tr><td>¿por qué?</td><td>pourquoi ?</td></tr><tr><td>¿para qué?</td><td>dans quel but ?</td></tr><tr><td>¿cuál? / ¿cuáles?</td><td>lequel / lesquels ?</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Tous les mots interrogatifs portent un accent écrit pour les distinguer de leurs équivalents conjonctifs : <em>que</em> (que), <em>donde</em> (où), <em>como</em> (comme).</p></div><h3 id="exemples" tabindex="-1">Exemples <a class="header-anchor" href="#exemples" aria-label="Permalink to “Exemples”">​</a></h3><blockquote><p><em>¿Dónde está el hotel?</em> — Où est l&#39;hôtel ? <em>¿Cuánto cuesta?</em> — Combien ça coûte ? <em>¿Cómo te llamas?</em> — Comment tu t&#39;appelles ? <em>¿Por qué estudias español?</em> — Pourquoi tu apprends l&#39;espagnol ?</p></blockquote>',23)])])}const h=e(s,[["render",r]]);export{c as __pageData,h as default};
